using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Tool state ──────────────────────────────────────────────────────────
var notes = new List<string>();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// ── Tools ───────────────────────────────────────────────────────────────
var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWebAsync, "search_web",
        "Search the web for information. Returns relevant snippets and summaries."),
    AIFunctionFactory.Create(SaveNote, "save_note",
        "Save a research note for later reference. Use this to record key findings."),
    AIFunctionFactory.Create(GetNotes, "get_notes",
        "Retrieve all saved research notes.")
};

// ── Chat client with automatic tool invocation ──────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ── Get research topic ──────────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agent ───────────────────────────────────────────────────────
var systemPrompt = """
    You are a research agent. Your job is to thoroughly research the given topic by:
    1. Searching the web for relevant information (make multiple searches with varied queries)
    2. Saving important findings as notes using the save_note tool
    3. After gathering enough information, retrieving your notes with get_notes and producing
       a well-structured, comprehensive summary

    Be thorough: search for multiple facets of the topic, save key facts and insights as
    individual notes, then compile everything into a final summary.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User,
        $"Please research the following topic and provide a comprehensive summary: {topic}")
};

var response = await client.GetResponseAsync(messages, new() { Tools = tools });

Console.WriteLine("\n📋 Research Summary:\n");
Console.WriteLine(response.Text);

// ── Tool implementations ────────────────────────────────────────────────

async Task<string> SearchWebAsync(
    [Description("The search query to find information about")] string query)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&t=ResearchAgent";
        var json = await httpClient.GetFromJsonAsync<JsonElement>(url);

        var results = new List<string>();

        if (json.TryGetProperty("Abstract", out var abs) &&
            abs.GetString() is { Length: > 0 } summary)
            results.Add($"[Summary] {summary}");

        if (json.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var t in topics.EnumerateArray().Take(8))
            {
                if (t.TryGetProperty("Text", out var text) &&
                    text.GetString() is { Length: > 0 } snippet)
                    results.Add(snippet);
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found. Try rephrasing or using different keywords.";
    }
    catch (Exception ex)
    {
        return $"Search error: {ex.Message}. Try a different query.";
    }
}

string SaveNote(
    [Description("The research note to save")] string note)
{
    notes.Add(note);
    Console.WriteLine($"  📝 Note saved ({notes.Count} total)");
    return $"Note saved. You now have {notes.Count} note(s).";
}

string GetNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";

    Console.WriteLine($"  📖 Reading {notes.Count} note(s)");
    var sb = new StringBuilder();
    for (var i = 0; i < notes.Count; i++)
        sb.AppendLine($"{i + 1}. {notes[i]}");
    return sb.ToString();
}

