 async Task<string> SearchWebAsync(
     [Description("The search query to find information about")] string query)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");
     try
     {
         var encoded = Uri.EscapeDataString(query);
         var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&t=ResearchAgent";
         var json = await httpClient.GetFromJsonAsync<JsonElement>(url);

         var results = new List<string>();

         if (json.TryGetProperty("Abstract", out var abs))
         {
             var summary = abs.GetString();
             if (!string.IsNullOrEmpty(summary))
                 results.Add($"[Summary] {summary}");
         }

         if (json.TryGetProperty("RelatedTopics", out var topics))
         {
             foreach (var t in topics.EnumerateArray().Take(8))
             {
                 if (t.TryGetProperty("Text", out var text))
                 {
                     var snippet = text.GetString();
                     if (!string.IsNullOrEmpty(snippet))
                         results.Add(snippet);
                 }
             }
         }

         return results.Count > 0
             ? string.Join("\n\n", results)
             : "No results found. Try rephrasing or using different keywords.";
     }
     catch (Exception ex)
     {
         return $"Search error: {ex.Message}. Try a different query.";
     }
 }

